const input = $input.first().json.body || $input.first().json || {};
const agentId = input.agent_id || 'agent_8001kdgp7qbyf4wvhs540be78vew';
const customScenarios = input.scenarios || null;

const defaultScenarios = [
  {
    id: 'happy_path_booking',
    name: 'Happy Path - Book Demo',
    category: 'happy_path',
    priority: 'critical',
    simulated_user_prompt: 'You are Mike, a pizza shop owner interested in AI voice agents for taking orders. You are friendly and willing to book a demo. When asked, confirm your name is Mike and agree to receive an SMS.',
    expected_tool_calls: ['send_sms'],
    evaluation_criteria: [
      { id: 'sms_sent', name: 'SMS Tool Called', type: 'prompt', conversation_goal_prompt: 'The agent successfully called the send_sms tool to send a text message', use_knowledge_base: false },
      { id: 'name_collected', name: 'Name Collected', type: 'prompt', conversation_goal_prompt: 'The agent collected the user first name before sending SMS', use_knowledge_base: false },
      { id: 'permission_asked', name: 'Permission Asked', type: 'prompt', conversation_goal_prompt: 'The agent asked permission before texting', use_knowledge_base: false }
    ]
  },
  {
    id: 'decline_sms',
    name: 'User Declines SMS',
    category: 'edge_case',
    priority: 'high',
    simulated_user_prompt: 'You are interested in AI voice agents but you do NOT want to receive any text messages. Politely decline when offered SMS. End the call without receiving a text.',
    expected_tool_calls: [],
    evaluation_criteria: [
      { id: 'no_sms_sent', name: 'No SMS Sent', type: 'prompt', conversation_goal_prompt: 'The agent did NOT call send_sms after user declined', use_knowledge_base: false },
      { id: 'graceful_exit', name: 'Graceful Exit', type: 'prompt', conversation_goal_prompt: 'The agent ended the conversation politely', use_knowledge_base: false }
    ]
  },
  {
    id: 'difficult_user',
    name: 'Difficult/Hostile User',
    category: 'stress_test',
    priority: 'medium',
    simulated_user_prompt: 'You are impatient and skeptical. Interrupt frequently. Ask aggressive questions about pricing. Test if the agent remains professional.',
    expected_tool_calls: [],
    evaluation_criteria: [
      { id: 'stays_professional', name: 'Stays Professional', type: 'prompt', conversation_goal_prompt: 'The agent remained calm and professional despite hostility', use_knowledge_base: false },
      { id: 'no_hallucination', name: 'No Hallucination', type: 'prompt', conversation_goal_prompt: 'The agent did not make up information', use_knowledge_base: false }
    ]
  }
];

const scenarios = customScenarios || defaultScenarios;
return [{ json: { agent_id: agentId, scenarios: scenarios, total_scenarios: scenarios.length, started_at: new Date().toISOString() } }];

const allResults = [];
const items = $input.all();

for (let i = 0; i < items.length; i++) {
  const response = items[i].json;
  const scenario = $('Split Scenarios').all()[i]?.json || {};
  const conversation = response.body?.simulated_conversation || response.simulated_conversation || [];
  const analysis = response.body?.analysis || response.analysis || {};
  const evaluation = analysis.evaluation_criteria_results || {};

  const actualToolCalls = [];
  for (const turn of conversation) {
    if (turn.tool_calls && turn.tool_calls.length > 0) {
      for (const tc of turn.tool_calls) {
        actualToolCalls.push(tc.tool_name || tc.name);
      }
    }
  }

  const expectedTools = scenario.expected_tool_calls || [];
  const actualSet = new Set(actualToolCalls);

  let toolAccuracy = 100;
  if (expectedTools.length > 0) {
    const matched = expectedTools.filter(t => actualSet.has(t)).length;
    toolAccuracy = (matched / expectedTools.length) * 100;
  } else if (actualToolCalls.length > 0) {
    toolAccuracy = 0;
  }

  const criteriaResults = [];
  let criteriaPassed = 0;
  let criteriaTotal = 0;

  for (const [criteriaId, result] of Object.entries(evaluation)) {
    criteriaTotal++;
    const passed = result.result === 'success' || result.result === true || (result.score && result.score >= 0.7);
    if (passed) criteriaPassed++;
    criteriaResults.push({ id: criteriaId, passed: passed, score: result.score || (passed ? 1 : 0), rationale: result.rationale || '' });
  }

  const criteriaScore = criteriaTotal > 0 ? (criteriaPassed / criteriaTotal) * 100 : 100;
  const callSuccessful = analysis.call_successful === 'success';
  const overallPassed = callSuccessful && toolAccuracy >= 80 && criteriaScore >= 70;

  let failurePattern = null;
  if (!overallPassed) {
    if (!callSuccessful) {
      failurePattern = 'CALL_FAILED';
    } else if (toolAccuracy < 80 && expectedTools.includes('send_sms') && !actualSet.has('send_sms')) {
      failurePattern = 'TOOL_NOT_CALLED';
    } else if (toolAccuracy < 80 && !expectedTools.includes('send_sms') && actualSet.has('send_sms')) {
      failurePattern = 'SMS_AFTER_DECLINE';
    } else if (criteriaScore < 70) {
      failurePattern = 'CRITERIA_FAILED';
    } else {
      failurePattern = 'UNKNOWN';
    }
  }

  const transcript = conversation.map(t => `${t.role}: ${t.message || '[tool call]'}`).join('\n');

  allResults.push({ json: { scenario_id: scenario.id, scenario_name: scenario.name, category: scenario.category, priority: scenario.priority, passed: overallPassed, call_successful: callSuccessful, tool_accuracy: toolAccuracy, criteria_score: criteriaScore, expected_tools: expectedTools, actual_tools: actualToolCalls, criteria_results: criteriaResults, failure_pattern: failurePattern, transcript: transcript, turn_count: conversation.length, summary: analysis.transcript_summary || '' } });
}

return allResults;

const results = $input.all().map(i => i.json);

const passed = results.filter(r => r.passed).length;
const failed = results.filter(r => !r.passed).length;
const total = results.length;
const passRate = total > 0 ? ((passed / total) * 100).toFixed(1) : '0.0';

const failuresByPattern = {};
const failures = results.filter(r => !r.passed);
for (const f of failures) {
  const pattern = f.failure_pattern || 'UNKNOWN';
  if (!failuresByPattern[pattern]) failuresByPattern[pattern] = [];
  failuresByPattern[pattern].push({ scenario_id: f.scenario_id, scenario_name: f.scenario_name, category: f.category, transcript: f.transcript, tool_calls: f.actual_tools });
}

const patternCounts = Object.entries(failuresByPattern).map(([name, items]) => ({ name, count: items.length })).sort((a, b) => b.count - a.count);
const dominantPattern = patternCounts[0]?.name || null;

const avgToolAccuracy = results.length > 0 ? results.reduce((sum, r) => sum + r.tool_accuracy, 0) / results.length : 100;
const avgCriteriaScore = results.length > 0 ? results.reduce((sum, r) => sum + r.criteria_score, 0) / results.length : 100;

const needsAutocorrection = failed > 0 && (parseFloat(passRate) < 80 || avgToolAccuracy < 85);

return [{ json: { summary: { total_scenarios: total, passed: passed, failed: failed, pass_rate: passRate + '%', avg_tool_accuracy: avgToolAccuracy.toFixed(1) + '%', avg_criteria_score: avgCriteriaScore.toFixed(1) + '%' }, failures_by_pattern: failuresByPattern, pattern_counts: patternCounts, dominant_pattern: dominantPattern, needs_autocorrection: needsAutocorrection, agent_id: $('Load Test Scenarios').item.json.agent_id, detailed_results: results, completed_at: new Date().toISOString() } }];
